+        minPrice = null;
+        maxPrice = null;
+        inStockOnly = false;
+        currentPage = 1;
+        await LoadDataAsync();
+    }
+
+    private async Task OnSortChanged()
+    {
+        currentPage = 1;
+        await LoadDataAsync();
+    }
+
+    private async Task GoToPage(int page)
+    {
+        if (page < 1 || page > totalPages) return;
+        currentPage = page;
+        await LoadDataAsync();
+    }
+
